/**
 * Plays a short notification beep when a new order arrives.
 * Uses an embedded WAV (data URL) so it works in production without external file paths.
 * Creates a fresh Audio instance per play to avoid reuse bugs (sound only playing for first order).
 * Uses Web Audio API gain for kitchen-level volume (louder than HTML5 Audio max).
 */

const BEEP_DATA_URL =
  "data:audio/wav;base64,";

/** Gain multiplier for kitchen environment (HTML5 Audio max is 1.0). */
const KITCHEN_GAIN = 2.5;

let cachedBuffer: AudioBuffer | null = null;
let audioContext: AudioContext | null = null;

function getAudioContext(): AudioContext | null {
  if (typeof window === "undefined") return null;
  if (!audioContext) {
    try {
      audioContext = new (window.AudioContext || (window as any).webkitAudioContext)();
    } catch {
      return null;
    }
  }
  return audioContext;
}

async function getCachedBuffer(): Promise<AudioBuffer | null> {
  if (cachedBuffer) return cachedBuffer;
  const ctx = getAudioContext();
  if (!ctx) return null;
  try {
    const res = await fetch(BEEP_DATA_URL);
    const arrayBuffer = await res.arrayBuffer();
    cachedBuffer = await ctx.decodeAudioData(arrayBuffer);
    return cachedBuffer;
  } catch {
    return null;
  }
}

/**
 * Preloads the notification sound so it plays immediately on the first new order.
 * Call this when KitchenView mounts.
 */
export function preloadNotificationSound(): void {
  getCachedBuffer();
}

/**
 * Plays the notification beep once. Uses a fresh playback each time (no reuse)
 * so every new order triggers the sound. Uses Web Audio API gain for kitchen-level volume.
 */
export function playNotificationBeep(): void {
  const ctx = getAudioContext();
  if (!ctx) {
    fallbackPlay();
    return;
  }
  const doPlay = (buffer: AudioBuffer) => {
    try {
      const source = ctx!.createBufferSource();
      source.buffer = buffer;
      const gainNode = ctx!.createGain();
      gainNode.gain.value = KITCHEN_GAIN;
      source.connect(gainNode);
      gainNode.connect(ctx!.destination);
      source.start(0);
    } catch {
      fallbackPlay();
    }
  };
  getCachedBuffer()
    .then((buffer) => {
      if (!buffer) {
        fallbackPlay();
        return;
      }
      if (ctx!.state === "suspended") {
        ctx!.resume().then(() => doPlay(buffer)).catch(() => fallbackPlay());
      } else {
        doPlay(buffer);
      }
    })
    .catch(() => fallbackPlay());
}

/** Fallback: new Audio instance per play when Web Audio API fails. */
function fallbackPlay(): void {
  try {
    const audio = new Audio(BEEP_DATA_URL);
    audio.volume = 1.0;
    audio.play().catch(() => {});
  } catch {
    // Ignore
  }
}
